export function getFormatBySlug(slug: string): ImageFormat | undefined {
  return formats.find((format) => format.slug === slug);
}

export function getAllFormatSlugs(): string[] {
  return formats.map((format) => format.slug);
}

export function getRelatedFormats(slug: string, count: number = 5): ImageFormat[] {
  const currentFormat = getFormatBySlug(slug);
  if (!currentFormat) return [];
  
  const related = formats
    .filter((format) => format.slug !== slug && format.category === currentFormat.category)
    .slice(0, count);
  
  // If we don't have enough related formats in the same category, add from other categories
  if (related.length < count) {
    const additional = formats
      .filter((format) => format.slug !== slug && !related.includes(format))
      .slice(0, count - related.length);
    related.push(...additional);
  }
  
  return related;
}

export function getPopularFormats(count: number = 8): ImageFormat[] {
  const curatedSlugs = [
    'instagram-post',
    'instagram-story',
    'youtube-thumbnail',
    'facebook-post',
    'linkedin-post',
    'pinterest-pin',
    'tiktok-video',
    'website-hero',
  ];

  const curated = curatedSlugs
    .map((slug) => getFormatBySlug(slug))
    .filter((format): format is ImageFormat => Boolean(format));

  if (curated.length >= count) {
    return curated.slice(0, count);
  }

  const fallback = formats.filter(
    (format) => !curated.some((item) => item.slug === format.slug)
  );

  return [...curated, ...fallback].slice(0, count);
}


